import { useEffect, useState } from "react";
import { api, getAuthToken } from "../api";

export default function Profile() {
  const [profile, setProfile] = useState(null);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [mobileNumber, setMobileNumber] = useState("");
  const [otpCode, setOtpCode] = useState("");

  useEffect(() => {
    const fetchProfile = async () => {
      if (!getAuthToken()) {
        setError("Please login to view your profile.");
        return;
      }

      try {
        const res = await api.get("/auth/profile/");
        setProfile(res.data);
        setMobileNumber(res.data.mobile_number || "");
      } catch (err) {
        setError("Unable to load profile.");
      }
    };

    fetchProfile();
  }, []);

  const saveMobile = async () => {
    try {
      setError("");
      const res = await api.patch("/auth/profile/", { mobile_number: mobileNumber.trim() });
      setProfile(res.data);
      setMessage("Mobile number saved. Please verify with OTP.");
      setTimeout(() => setMessage(""), 2500);
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to save mobile number.");
    }
  };

  const sendOtp = async () => {
    try {
      setError("");
      await api.post("/auth/send-otp/", { mobile_number: mobileNumber.trim() });
      setMessage("OTP sent successfully.");
      setTimeout(() => setMessage(""), 2500);
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to send OTP.");
    }
  };

  const verifyOtp = async () => {
    try {
      setError("");
      await api.post("/auth/verify-otp/", {
        mobile_number: mobileNumber.trim(),
        code: otpCode.trim(),
      });
      const res = await api.get("/auth/profile/");
      setProfile(res.data);
      setMessage("Mobile verified successfully.");
      setOtpCode("");
      setTimeout(() => setMessage(""), 2500);
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to verify OTP.");
    }
  };

  return (
    <div className="page">
      <div className="page-header">
        <h1>👤 My Profile</h1>
        <p>Manage your account information</p>
      </div>

      {error && <div className="error-message">{error}</div>}
      {message && <div className="success-message">{message}</div>}
      
      {profile ? (
        <div className="profile-card">
          <div className="profile-field">
            <label>Username</label>
            <div className="profile-field-value">{profile.username}</div>
          </div>
          
          <div className="profile-field">
            <label>Email Address</label>
            <div className="profile-field-value">{profile.email || "Not provided"}</div>
          </div>

          <div className="profile-field">
            <label>Role</label>
            <div className="profile-field-value">{(profile.role || "buyer").toUpperCase()}</div>
          </div>

          <div className="profile-field">
            <label>Mobile Number</label>
            <input
              type="tel"
              value={mobileNumber}
              onChange={(e) => setMobileNumber(e.target.value)}
              placeholder="Enter mobile number"
            />
            <div className="form-actions" style={{ marginTop: 8 }}>
              <button className="btn-action btn-secondary" onClick={saveMobile}>Save Mobile</button>
              <button className="btn-action btn-add-cart" onClick={sendOtp}>Send OTP</button>
            </div>
          </div>

          <div className="profile-field">
            <label>Verify Mobile OTP</label>
            <input
              type="text"
              value={otpCode}
              onChange={(e) => setOtpCode(e.target.value)}
              placeholder="Enter 6-digit OTP"
            />
            <button className="btn-action btn-add-cart" onClick={verifyOtp}>Verify OTP</button>
            <div className="profile-field-value" style={{ color: profile.is_mobile_verified ? '#1aa260' : '#a23636' }}>
              {profile.is_mobile_verified ? "✓ Mobile Verified" : "✗ Mobile Not Verified"}
            </div>
          </div>

          <div className="profile-field">
            <label>Account Status</label>
            <div className="profile-field-value" style={{color: '#1aa260', fontWeight: '700'}}>✓ Active</div>
          </div>
        </div>
      ) : error ? null : (
        <div className="empty-state">
          <div className="empty-icon">👤</div>
          <h3>Loading profile...</h3>
        </div>
      )}
    </div>
  );
}
